INSERT INTO reviews (id, name, password_hash, rating, category, comment, image_url_1, image_url_2, created_at) VALUES
-- 눈썹 디자인
('seed-review-001', '김*연', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '눈썹 디자인', '원래 눈썹이 옅어서 메이크업할 때마다 그리는 게 번거로웠는데, 엠보 결 기법으로 받고 나니 아침에 시간이 꽤 줄었어요. 색도 점점 자연스럽게 올라오고 주변에서도 잘했다고 하더라고요.', NULL, NULL, '2025-11-08 14:20:00'),
('seed-review-002', '이*진', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '눈썹 디자인', '처음이라 긴장했는데 상담 때 제 얼굴형에 맞는 디자인을 충분히 설명해 주셔서 믿고 맡겼습니다. 시술 중에도 불편함 없이 세심하게 챙겨 주셨고 결과도 과하지 않아서 만족해요.', NULL, NULL, '2025-12-03 11:05:00'),
('seed-review-003', '박*아', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 4, '눈썹 디자인', '콤보로 받았는데 처음 며칠은 조금 진하게 느껴졌지만 안내해 주신 대로 관리하니 딱 제가 원하던 톤이 됐어요. 예약제라 대기 없이 편하게 받은 점도 좋았습니다.', NULL, NULL, '2026-01-15 16:40:00'),
('seed-review-004', '최*희', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '눈썹 디자인', '눈썹 결 하나하나가 인위적이지 않아서 사진 찍을 때 특히 만족도가 높아요. 사후 관리 안내도 카톡으로 다시 보내주셔서 집에서도 헷갈리지 않았습니다.', NULL, NULL, '2026-02-22 10:30:00'),

-- 브로우 메이크업
('seed-review-005', '정*우', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '브로우 메이크업', '남자 눈썹이라 티 나면 부담스러울까 봐 걱정했는데, 골격에 맞춰 정돈된 느낌으로 나와서 오히려 인상이 깔끔해졌어요. 주변에서 눈썹 정리한 거냐고 물어볼 정도입니다.', NULL, NULL, '2025-10-19 13:15:00'),
('seed-review-006', '한*석', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '브로우 메이크업', '운동 후 땀 흘리는 날이 많아서 반영구를 망설였는데, 회복 기간 안내도 꼼꼼했고 결과도 무너지지 않고 유지되고 있어요. 상담부터 친절해서 재방문 의사 있습니다.', NULL, NULL, '2025-11-27 09:50:00'),
('seed-review-007', '윤*민', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 4, '브로우 메이크업', '처음 디자인 시안을 보고 조금 더 각 있게 해달라고 요청했는데 바로 반영해 주셔서 좋았습니다. 샵 분위기도 조용하고 프라이빗해서 편하게 받을 수 있었어요.', NULL, NULL, '2026-01-08 18:20:00'),
('seed-review-008', '강*현', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '브로우 메이크업', '비대면으로 사진 보내고 견적 상담받은 뒤 방문했는데, 실제로 보니 상태 파악이 정확하셨더라고요. 남성 고객도 세심하게 케어해 주셔서 믿음이 갔습니다.', NULL, NULL, '2026-03-05 15:00:00'),

-- 두피 케어
('seed-review-009', '오*라', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '두피 케어', '정수리 가르마 쪽이 비쳐서 사진 찍을 때마다 신경 쓰였는데, 두피 커버 케어 후에는 조명 아래에서도 훨씬 자연스러워졌어요. 가까이서 봐도 어색하지 않습니다.', NULL, NULL, '2025-09-14 12:30:00'),
('seed-review-010', '서*영', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '두피 케어', '미용실에서 머리 감을 때 두피가 너무 도드라져 보인다는 말을 들어서 고민하다가 방문했습니다. 세션은 조금 길었지만 중간에 쉬는 시간도 주셔서 편했고 결과에 만족합니다.', NULL, NULL, '2025-12-18 17:10:00'),
('seed-review-011', '임*수', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 4, '두피 케어', '처음엔 도트가 뭉친 느낌이 들까 걱정했는데, 회복되면서 점점 실제 모근처럼 보이더라고요. 관리 방법을 자세히 알려주셔서 집에서도 실수 없이 지킬 수 있었습니다.', NULL, NULL, '2026-02-01 14:45:00'),
('seed-review-012', '조*원', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '두피 케어', '출근 전 아침에 머리숱 채우는 제품 쓰는 게 일상이었는데, 이제는 그런 번거로움이 많이 줄었어요. 색감도 제 머리색이랑 잘 맞아서 만족도가 높습니다.', NULL, NULL, '2026-03-12 11:20:00'),

-- 헤어라인 디자인
('seed-review-013', '배*은', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '헤어라인 디자인', '이마 라인이 들쭉날쭉해서 앞머리 스타일이 제한됐는데, 쉐이딩 느낌으로 자연스럽게 정리돼서 얼굴이 작아 보인다는 말을 들었어요. 디자인 상담이 꼼꼼했습니다.', NULL, NULL, '2025-10-28 10:00:00'),
('seed-review-014', '문*지', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '헤어라인 디자인', '생각보다 아프지 않았고, 시술 후 붓기 관리법도 친절하게 안내해 주셨어요. 한 달 정도 지나니 주변에서 헤어라인이 예뻐졌다는 이야기를 들었습니다.', NULL, NULL, '2025-11-16 16:25:00'),
('seed-review-015', '황*연', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 4, '헤어라인 디자인', '처음에는 진하게 느껴져서 걱정했는데 회복되면서 자연스러운 음영으로 바뀌었습니다. 예약 시간 맞춰 바로 진행돼서 대기 스트레스가 없었던 점도 좋았어요.', NULL, NULL, '2026-01-24 13:50:00'),
('seed-review-016', '신*아', '42a2ec11e48541d0e9d3fb78af3b764af8b458fe0ce3d589d161cfe20d7635f5', 5, '헤어라인 디자인', '옆모습 사진이 부담스러웠는데 이제는 머리 묶어도 라인이 깔끔해 보여요. 그레이스샵 분위기가 차분해서 처음 받는 분들도 편할 것 같아요.', NULL, NULL, '2026-02-14 09:15:00');
